mapper.select:
SELECT 
FROM hub_collect_schedule s
JOIN users u ON u.id = s.user_id
WHERE s.user_id = #{userId}
  AND s.id = #{id}

mapper.insert:
INSERT INTO hub_collect_schedule (
    user_id, schedule_name, mall_keys, date_range_type, run_time, enabled_yn, next_run_at
) VALUES (
    #{userId}, #{scheduleName}, CAST(#{mallKeysJson} AS jsonb), #{dateRangeType},
    #{runTime}, #{enabledYn}, #{nextRunAtValue}
)

mapper.delete:
DELETE FROM hub_collect_schedule
WHERE user_id = #{userId}
  AND id = #{id}

mapper.update:
UPDATE hub_collect_schedule_run_log
SET status = 'FAILED',
    finished_at = NOW(),
    error_message = #{errorMessage}
WHERE id = #{id}
